// webgl-fluid 需要真实 canvas，不能把宿主 div 直接传给 getContext
const el = document.getElementById('fluid'); el.style.height = `${spec.height ?? 400}px`;
const canvas = document.createElement('canvas'); canvas.style.cssText = 'display:block;width:100%;height:100%'; el.appendChild(canvas); canvas.width = el.clientWidth || 600; canvas.height = el.clientHeight || 400;
const { default: WebGLFluid } = await import('https://cdn.jsdelivr.net/npm/webgl-fluid@0.4.0/+esm');
WebGLFluid(canvas, { TRIGGER: data.TRIGGER ?? 'hover', DENSITY_DISSIPATION: data.DENSITY_DISSIPATION ?? 1, VELOCITY_DISSIPATION: data.VELOCITY_DISSIPATION ?? 0.3, CURL: data.CURL ?? 30, SPLAT_RADIUS: data.SPLAT_RADIUS ?? 0.35, COLORFUL: data.COLORFUL ?? true, BACK_COLOR: data.BACK_COLOR ?? { r: 0, g: 0, b: 0 }, TRANSPARENT: data.TRANSPARENT ?? false });

